    return new Matcher(spec, version)
  }
}

function compile (spec: string): {
  regex: string
  props: string[]
} {
  const parts: string[] = []
  const props: string[] = []
  let min = 0
  let max = 0
  let any = false
  let opt = true
  function flatten (final: boolean = false): void {
    if (max > 0 || any) {
      if (final && opt && min < 1) {
        min = 1
      } else if (min > 0) {
        opt = false
      }
      parts.push(any
        ? min < 2
          ? min < 1
            ? '(?:/[^/]+)*'
            : '(?:/[^/]+)+'
          : `(?:/[^/]+){${min},}`
        : max === 1
          ? min === 1
            ? '/[^/]+'
            : '(?:/[^/]+)?'
          : min === max
            ? `(?:/[^/]+){${min}}`
            : `(?:/[^/]+){${min},${max}}`)
    }
    min = 0
    max = 0
    any = false
  }
  function finalise (): string {
    flatten(true)
    return (opt ? '^/$|^' : '^') + parts.reduce((acc, seg) => seg + acc, '$')
  }
  for (const part of spec.split('/').slice(1).reverse()) {
    switch (part) {
      case '+':
        min++
        max++
        break
      case '++':
        max++
        break
      case '*':
        min++
        any = true
        break
      case '**':
        any = true
        break
      default:
        flatten()
        opt = false
        if (part.match(/:.+/) !== null) {
          props.push(part.slice(1))
          parts.push('/([^/]+)')
        } else {
          parts.push(`/${part.replace(/([.$])/g, '\\$1')}`)
        }
    }
  }
  return {
    regex: finalise(),
    props: props.reverse()
  }
